-- 服务配置
delete from G_SERVICES where SERVICE_ID in ('CIPS_04499', 'DTT_CAEA_PORT_OUT','DTT_CAEB_PORT_OUT','DTT_CAEA_PORT_IN','DTT_CAEB_PORT_IN','BIZ_CAEA_PORT_OUT','BIZ_CAEB_PORT_OUT','BIZ_CAEA_PORT_IN','BIZ_CAEB_PORT_IN','CIPS_PMTS_DTT_SND','CIPS_PMTS_DTT_RCV','CIPS_PORT_OUT_ROUTE');


-- 方法配置



-- 几个port的MQ参数
delete from G_SPARAS where APP_NAME like '%CAE%';



-- PMTS相关业务参数
delete from G_PARAS where PARA_KEY in ('PMTS_ROUTE_SWITCH', 'PMTS_DTT_INTERVAL', 'PMTS_DTT_FAIL_TIME', 'PMTS_ROUTE_STRATEGY', 'PMTS_DTT_LOG_RETENTION_DAYS');


-- 初始化PMTS节点表



-- 邮件提醒
delete from G_ROUTE where ROUTE_KEY in ('CIPS_PMTS_NODE_ABNORMAL', 'CIPS_PMTS_NODE_RECOVER');

delete from GNO_TOPIC where TOPIC in  ('CIPS_PMTS_NODE_ABNORMAL', 'CIPS_PMTS_NODE_RECOVER');


delete from GNO_TPL where TPL_ID in  ('CIPS_PMTS_NODE_ABNORMAL', 'CIPS_PMTS_NODE_RECOVER');


